require_once __DIR__.'/app/layout.php';require_once __DIR__.'/app/letter_template.php';require_login();$id=(int)($_GET['id']??0);$st=db()->prepare('SELECT a.*,e.name,e.nip,e.grade,e.position,e.signature_path FROM attendance_events a JOIN employees e ON e.id=a.employee_id WHERE a.id=?');$st->execute([$id]);$row=$st->fetch();if(!$row){http_response_code(404);exit('Surat tidak ditemukan.');}$employee=['name'=>$row['name'],'nip'=>$row['nip'],'grade'=>$row['grade'],'position'=>$row['position'],'signature_path'=>$row['signature_path']];$set=settings();page_header('Pratinjau Surat','events');?><div class="no-print actions-inline" style="justify-content:flex-end;margin-bottom:12px"><a class="btn ghost" href="events.php">Kembali</a><a class="btn secondary" href="letter_word.php?id=<?=$id?>">Unduh Word (.docx)</a><button class="btn" onclick="window.print()">Cetak / Simpan PDF</button></div><?php if($row['approval_status']==='approved' && empty($set['boss_signature_path'])):?><div class="no-print alert warn"><b>Tanda tangan Kepala Subdirektorat belum diunggah.</b> Surat sudah berstatus Disetujui, tetapi tanda tangan atasan baru akan muncul setelah diunggah melalui menu Pengaturan.</div><?php endif;?><div class="no-print alert"><b>Pengaturan cetak:</b> ukuran A4 Portrait, skala 100%, margin mengikuti dokumen, dan nonaktifkan opsi Header dan footer pada dialog cetak.</div><div class="preview-bg"><?=letter_html($row,$employee,$set)?></div><?php page_footer();
